// // This module implements a 64-bit binary counter that decrements on the rising edge of the clock when the enable signal is high. If the reset signal is high, the counter should reset to the maximum value of 2^64 - 1.
module counter_64bit (
    input clk,
    input reset,
    input enable,
    output reg [63:0] count
);
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            count <= 64'b0;
        end else if (enable) begin
            count <= count + 1;
        end
    end
endmodule
